import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';

function Home() {
    const navigate = useNavigate();
    const [resumo, setResumo] = useState({
        osAbertas: 0,
        osConcluidas: 0,
        totalClientes: 0,
        faturamentoMes: 0
    });
    const [ultimasOs, setUltimasOs] = useState([]);
    const [carregando, setCarregando] = useState(true);

    useEffect(() => {
        const carregarDados = async () => {
            try {
                const osRes = await api.get('/os');
                const todasOs = osRes.data;
                const clientesRes = await api.get('/clientes');
                const clientes = clientesRes.data;

                const abertas = todasOs.filter(os => os.status_os !== 'concluido' && os.status_os !== 'entregue').length;
                const concluidas = todasOs.filter(os => os.status_os === 'concluido' || os.status_os === 'entregue').length;

                const dataAtual = new Date();
                const mesAtual = dataAtual.getMonth();
                const anoAtual = dataAtual.getFullYear();
                const faturamento = todasOs.reduce((acc, os) => {
                    if (os.data_conclusao) {
                        const dataConclusao = new Date(os.data_conclusao);
                        if (dataConclusao.getMonth() === mesAtual && dataConclusao.getFullYear() === anoAtual) {
                            return acc + (parseFloat(os.preco_final) || 0);
                        }
                    }
                    return acc;
                }, 0);

                setResumo({
                    osAbertas: abertas,
                    osConcluidas: concluidas,
                    totalClientes: clientes.length,
                    faturamentoMes: faturamento
                });

                const ultimas = [...todasOs]
                    .sort((a, b) => new Date(b.data_abertura) - new Date(a.data_abertura))
                    .slice(0, 5);
                setUltimasOs(ultimas);
            } catch (error) {
                console.error(error);
            } finally {
                setCarregando(false);
            }
        };
        carregarDados();
    }, []);

    if (carregando) return <div style={{ textAlign: 'center', marginTop: 50 }}>Carregando...</div>;

    return (
        <div style={{ padding: '20px' }}>
            <h1>Dashboard - mwr Sistema</h1>
            <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap', marginBottom: '40px' }}>
                <div style={{ flex: 1, background: '#f0f8ff', padding: '20px', borderRadius: '10px' }}>
                    <h3>📋 OS Abertas</h3>
                    <p style={{ fontSize: '32px', fontWeight: 'bold' }}>{resumo.osAbertas}</p>
                </div>
                <div style={{ flex: 1, background: '#e6ffe6', padding: '20px', borderRadius: '10px' }}>
                    <h3>✅ OS Concluídas</h3>
                    <p style={{ fontSize: '32px', fontWeight: 'bold' }}>{resumo.osConcluidas}</p>
                </div>
                <div style={{ flex: 1, background: '#fff0e6', padding: '20px', borderRadius: '10px' }}>
                    <h3>👥 Clientes</h3>
                    <p style={{ fontSize: '32px', fontWeight: 'bold' }}>{resumo.totalClientes}</p>
                </div>
                <div style={{ flex: 1, background: '#f9e6ff', padding: '20px', borderRadius: '10px' }}>
                    <h3>💰 Faturamento (mês)</h3>
                    <p style={{ fontSize: '32px', fontWeight: 'bold' }}>R$ {resumo.faturamentoMes.toFixed(2)}</p>
                </div>
            </div>

            <div style={{ display: 'flex', gap: '15px', marginBottom: '40px' }}>
                <button onClick={() => navigate('/os/nova')} style={{ padding: '10px 20px', background: '#007bff', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>➕ Nova OS</button>
                <button onClick={() => navigate('/clientes/novo')} style={{ padding: '10px 20px', background: '#28a745', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>👤 Cadastrar Cliente</button>
                <Link to="/relatorios"><button style={{ padding: '10px 20px', background: '#ffc107', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>📊 Relatórios</button></Link>
            </div>

            <h2>Últimas OS</h2>
            {ultimasOs.length === 0 ? <p>Nenhuma OS cadastrada.</p> : (
                <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead style={{ background: '#f2f2f2' }}>
                        <tr><th>Nº OS</th><th>Cliente</th><th>Equipamento</th><th>Status</th><th>Data</th><th>Valor</th></tr>
                    </thead>
                    <tbody>
                        {ultimasOs.map(os => (
                            <tr key={os.id}>
                                <td>{os.numero_os}</td>
                                <td>{os.cliente_nome || '—'}</td>
                                <td>{os.equipamento} {os.modelo}</td>
                                <td>{os.status_os}</td>
                                <td>{new Date(os.data_abertura).toLocaleDateString()}</td>
                                <td>R$ {parseFloat(os.preco_final).toFixed(2)}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            )}
        </div>
    );
}

export default Home;
